// A note landed in the vault. If it is a FINISHED result from a delegated agent
// (kuli/pakprof), push it back into the Telegram chat so the handoff is not a
// dead end. The assistant's own output is skipped: you already saw that reply in
// the chat when it answered you directly.
//
// This never triggers an agent, so it cannot loop with the vault-watch workflow:
// that one only acts on status "open", this one only on status "done".
//
// Needs two env vars on the n8n service:
//   TELEGRAM_BOT_TOKEN - the same bot as the assistant. Sending is a separate API
//                        call from receiving, so it does NOT conflict with the
//                        hermes native bot polling for updates on that token.
//   TELEGRAM_CHAT_ID   - where to deliver. The agents never learn your chat id,
//                        so it is configured, not inferred.
const fs = require('fs');

const token = $env.TELEGRAM_BOT_TOKEN;
const chatId = $env.TELEGRAM_CHAT_ID;
if (!token || !chatId) return [];

const path = ($input.first().json.path || '').toString();
if (!path.endsWith('.md')) return [];

// Identify the assistant (the route flagged default) so we can skip its own notes.
let routes = {};
try { if ($env.GHIATH_ROUTES) routes = JSON.parse($env.GHIATH_ROUTES); } catch (e) {}
const assistant = Object.keys(routes).find(a => routes[a].default);

let raw;
try {
  raw = fs.readFileSync(path, 'utf8');
} catch (e) {
  // Unreadable (e.g. caught mid-write); skip rather than send a truncated note.
  return [];
}

const fm = raw.match(/^---\n([\s\S]*?)\n---/);
if (!fm) return [];
const field = (k) => {
  const m = fm[1].match(new RegExp('^' + k + ':\\s*(.+)$', 'm'));
  return m ? m[1].trim().toLowerCase() : '';
};

// Only completed results, and only from an agent other than the assistant.
if (field('status') !== 'done') return [];
if (field('type') !== 'result') return [];
const owner = field('owner');
if (!owner || owner === assistant) return [];

// Body without the front-matter. Telegram hard-caps a message at 4096 chars.
const body = raw.slice(fm[0].length).trim();
const note = path.replace('/data/vault/', '');
const header = `\u2705 ${owner} finished a task\n${note}\n\n`;
const room = 3900 - header.length;
const text = header + (body.length > room ? body.slice(0, room) + '\n\n[...truncated, full note in the vault]' : body);

return [{ json: { url: `https://api.telegram.org/bot${token}/sendMessage`, chatId, text, note, owner } }];
